function clampNumber(value, min, max) {
  const parsed = Number(value);
  if (Number.isNaN(parsed)) return min;
  return Math.min(max, Math.max(min, parsed));
}

function getProgram(type) {
  return PROGRAMS[type] || PROGRAMS["healing-vacation"];
}

function distributeNights(durationDays, program) {
  const nights = Math.max(4, durationDays - 1);
  const base = [...program.defaultNights];
  const baseTotal = base.reduce((sum, item) => sum + item, 0);

  if (nights === baseTotal) return base;
  if (nights < baseTotal) {
    let remaining = baseTotal - nights;
    for (let i = base.length - 1; i >= 0 && remaining > 0; i -= 1) {
      const reducible = Math.max(0, base[i] - 1);
      const cut = Math.min(reducible, remaining);
      base[i] -= cut;
      remaining -= cut;
    }
    return base;
  }

  let extra = nights - baseTotal;
  let cursor = 0;
  while (extra > 0) {
    base[cursor % base.length] += 1;
    cursor += 1;
    extra -= 1;
  }
  return base;
}

function rankPlace(place, programType, preferences) {
  const healingWeight = preferences.healing / 5;
  const vacationWeight = preferences.vacation / 5;
  const premiumWeight = preferences.comfort / 5;
  const fitBonus = place.fit.includes(programType) ? 2 : -1;

  return (
    place.score.healing * healingWeight +
    place.score.vacation * vacationWeight +
    place.score.premium * premiumWeight +
    place.score.efficiency * 0.6 +
    fitBonus
  );
}

function buildDayPlan(programType, durationDays, preferences) {
  const resolvedProgramType = PROGRAMS[programType] ? programType : "healing-vacation";
  const program = getProgram(resolvedProgramType);
  const days = clampNumber(durationDays, 5, 8);
  const sportTypes = normalizeSportTypes(preferences.sports);
  const sportPlaces = selectSportPlaces(resolvedProgramType, sportTypes);
  const routeRegions = optimizeRegions(program.regions, sportPlaces.map((place) => place.region), resolvedProgramType);
  const nights = distributeNightsForRegions(days, routeRegions, program);
  const route = routeRegions.map((region, index) => ({
    region,
    label: REGION_LABELS[region],
    nights: nights[index],
  }));
  const routeStats = calculateRouteStats(routeRegions, resolvedProgramType);

  const selected = PLACES
    .filter((place) => routeRegions.includes(place.region) || program.required.includes(place.id) || sportPlaces.some((sport) => sport.id === place.id))
    .map((place) => ({
      ...place,
      rank: rankPlace(place, resolvedProgramType, preferences),
      status: getPlaceStatus(place, program, sportPlaces),
    }))
    .sort((a, b) => b.rank - a.rank);

  const excluded = PLACES
    .filter((place) => program.excluded.includes(place.id))
    .map((place) => ({
      ...place,
      reason: getExclusionReason(place.id, resolvedProgramType),
    }));

  return {
    program,
    route,
    selected,
    excluded,
    programType: resolvedProgramType,
    routeStats,
    sportPlaces,
    days: createItinerary(resolvedProgramType, days, route, sportPlaces),
  };
}

function normalizeSportTypes(sports = []) {
  if (!Array.isArray(sports)) return [];
  return sports.filter((sport) => ["tennis", "golf"].includes(sport));
}

function selectSportPlaces(programType, sports) {
  const preferred = {
    "healing-vacation": { tennis: "liga-tennis-nusa-dua", golf: "bukit-pandawa-golf" },
    "subconscious-healing": { tennis: "liga-tennis-nusa-dua", golf: "bukit-pandawa-golf" },
    "deep-healing": { tennis: "liga-tennis-umalas", golf: "new-kuta-golf" },
    "sport-reset": { tennis: "liga-tennis-umalas", golf: "new-kuta-golf" },
  };

  return sports.flatMap((sport) => {
    const candidates = PLACES
      .filter((place) => SPORT_PLACE_CANDIDATES[sport]?.includes(place.id))
      .sort((a, b) => {
        if (preferred[programType]?.[sport] === a.id) return -1;
        if (preferred[programType]?.[sport] === b.id) return 1;
        const fitDiff = Number(b.fit.includes(programType)) - Number(a.fit.includes(programType));
        if (fitDiff !== 0) return fitDiff;
        return b.score.efficiency + b.score.premium - (a.score.efficiency + a.score.premium);
      });
    return candidates.slice(0, 1);
  });
}

function getPlaceStatus(place, program, sportPlaces) {
  if (program.required.includes(place.id)) return "必去";
  if (sportPlaces.some((sport) => sport.id === place.id)) return place.type === "golf" ? "高尔夫" : "网球";
  return "可选";
}

function optimizeRegions(baseRegions, extraRegions, programType) {
  const uniqueRegions = [...new Set([...baseRegions, ...extraRegions])].filter(Boolean);
  if (uniqueRegions.length <= 2) return uniqueRegions;

  const permutations = permute(uniqueRegions);
  const scored = permutations.map((regions) => {
    const stats = calculateRouteStats(regions, programType);
    return { regions, score: stats.totalMinutes + stats.flowPenalty };
  });
  scored.sort((a, b) => a.score - b.score);
  return scored[0].regions;
}

function calculateRouteStats(regions, programType) {
  const legs = [];
  let totalMinutes = 0;
  const fullRoute = ["airport", ...regions, "airport"];

  for (let index = 0; index < fullRoute.length - 1; index += 1) {
    const from = fullRoute[index];
    const to = fullRoute[index + 1];
    const minutes = getTravelMinutes(from, to);
    totalMinutes += minutes;
    legs.push({ from, to, minutes });
  }

  const flowPenalty = getFlowPenalty(regions, programType);
  return {
    legs,
    totalMinutes,
    flowPenalty,
    optimizedScore: totalMinutes + flowPenalty,
  };
}

function getTravelMinutes(from, to) {
  if (from === to) return 0;
  return REGION_TRAVEL_MINUTES[from]?.[to] ?? REGION_TRAVEL_MINUTES[to]?.[from] ?? 120;
}

function getFlowPenalty(regions, programType) {
  let penalty = 0;
  const startsInUbud = regions[0] === "ubud";
  const endsInUluwatu = regions[regions.length - 1] === "uluwatu";

  if ((programType === "healing-vacation" || programType === "subconscious-healing" || programType === "deep-healing") && !startsInUbud) penalty += 35;
  if ((programType === "healing-vacation" || programType === "subconscious-healing" || programType === "deep-healing") && !endsInUluwatu) penalty += 25;
  if (regions.includes("nusa-dua") && regions.includes("seseh")) penalty += 30;
  if (regions.length > 4) penalty += 20;
  return penalty;
}

function permute(items) {
  if (items.length <= 1) return [items];
  return items.flatMap((item, index) => {
    const rest = [...items.slice(0, index), ...items.slice(index + 1)];
    return permute(rest).map((order) => [item, ...order]);
  });
}

function distributeNightsForRegions(durationDays, regions, program) {
  const nights = Math.max(4, durationDays - 1);
  const base = regions.map((region) => {
    const programIndex = program.regions.indexOf(region);
    if (programIndex >= 0) return Math.max(1, program.defaultNights[programIndex]);
    if (region === "nusa-dua") return 2;
    return 1;
  });
  let total = base.reduce((sum, value) => sum + value, 0);

  while (total > nights) {
    const index = findLargestReducibleIndex(base);
    if (index === -1) break;
    base[index] -= 1;
    total -= 1;
  }

  let cursor = 0;
  while (total < nights) {
    base[cursor % base.length] += 1;
    cursor += 1;
    total += 1;
  }

  return base;
}

function findLargestReducibleIndex(values) {
  let index = -1;
  let max = 1;
  values.forEach((value, currentIndex) => {
    if (value > max) {
      index = currentIndex;
      max = value;
    }
  });
  return index;
}

function getExclusionReason(placeId, programType) {
  if (programType === "healing-vacation" && placeId === "udara") {
    return "与 Nusa Dua 横向拉扯，适合独立深度疗愈路线。";
  }
  if (programType === "subconscious-healing" && placeId === "udara") {
    return "潜意识疗愈需要安全感和整合时间，Udara 更适合作为深度旅修线。";
  }
  if (programType === "healing-vacation" && placeId === "bynd") {
    return "健身房会削弱轻度假和舒适疗愈主线。";
  }
  if (programType === "subconscious-healing" && placeId === "bynd") {
    return "运动强刺激会打断潜意识疗愈的内在探索节奏。";
  }
  if (placeId === "grand-hyatt") {
    return "舒适度假价值高，但不适合纯深修或运动恢复路线。";
  }
  return "不符合当前路线主线，建议做选配或另一条产品线。";
}

function createItinerary(programType, durationDays, route, sportPlaces = []) {
  const templates = {
    "healing-vacation": [
      ["乌布", "抵达与降速", "接机、入住乌布、欢迎晚餐和状态访谈。"],
      ["乌布", "瑜伽与身体放松", "The Yoga Barn 呼吸/阴瑜伽，下午 Bali Botanica 或 Putri Bali Spa。"],
      ["乌布", "声音与自然整合", "Pyramids of Chi 或酒店内音疗，下午 Bali Pulina / 稻田轻体验。"],
      ["Nusa Dua", "舒适度假缓冲", "转场 Grand Hyatt Bali，泳池、沙滩和自由晚餐。"],
      ["Nusa Dua", "海边恢复日", "慢早餐、海边散步、酒店 SPA 或 La Nusa Bali Spa。"],
      ["Uluwatu", "悬崖收束", "转场 Uluwatu，The Istana 水疗/冷热浴，傍晚日落。"],
      ["返程", "旅后整合", "早餐、旅后 7 天建议、送机。"],
      ["选配", "延展日", "补充摄影、私享复盘或酒店自由日。"],
    ],
    "deep-healing": [
      ["乌布", "抵达与降速", "接机、入住乌布、欢迎晚餐和状态访谈。"],
      ["乌布", "声音疗愈", "Pyramids of Chi，下午稻田散步或轻 SPA。"],
      ["乌布", "瑜伽与净化", "The Yoga Barn，下午圣泉/古树/自然冥想三选一。"],
      ["Seseh", "海边排毒", "转场 Udara Bali，桑拿、海边瑜伽或 sound dome。"],
      ["Uluwatu", "山海打开", "转场 Uluwatu，悬崖酒店和日落。"],
      ["Uluwatu", "深度收束", "The Istana 水疗、冷热浴和最后复盘。"],
      ["返程", "旅后整合", "早餐、旅后 7 天建议、送机。"],
      ["选配", "延展日", "补充静默半日或一对一咨询。"],
    ],
    "subconscious-healing": [
      ["乌布", "抵达与安全感建立", "接机、入住乌布、欢迎晚餐和潜意识主题访谈。"],
      ["乌布", "身体放松与状态扫描", "Bali Botanica 身体护理，下午做情绪和身体信号记录。"],
      ["乌布", "潜意识入口", "Pyramids of Chi 声音疗愈或冥想，引导个人议题浮现。"],
      ["Nusa Dua", "安全感整合", "转场 Grand Hyatt Bali，泳池、沙滩和低刺激自由时间。"],
      ["Nusa Dua", "身体安顿日", "慢早餐、海边散步、轻 SPA，保留写作和复盘时间。"],
      ["Uluwatu", "释放与收束", "转场 Uluwatu，The Istana 水疗/冷热浴，傍晚做释放仪式。"],
      ["返程", "旅后行动脚本", "早餐、旅后 7 天潜意识练习建议、送机。"],
      ["选配", "延展日", "补充一对一咨询、摄影或静默半日。"],
    ],
    "sport-reset": [
      ["乌布", "抵达与恢复", "接机、入住乌布、轻晚餐。"],
      ["乌布", "瑜伽启动", "The Yoga Barn，下午身体护理。"],
      ["Canggu", "海边运动", "转场 Canggu / Seseh，BYND Fitness 轻训练。"],
      ["Seseh", "排毒恢复", "Udara Bali 桑拿、水疗、海边瑜伽。"],
      ["Uluwatu", "悬崖打开", "转场 Uluwatu，日落和自由休息。"],
      ["Uluwatu", "水疗收束", "The Istana，冷热浴和神经系统恢复。"],
      ["返程", "旅后整合", "早餐、训练/休息建议、送机。"],
      ["选配", "延展日", "冲浪、摄影或私教体验。"],
    ],
  };

  const days = templates[programType].slice(0, durationDays).map((item, index) => ({
    day: index + 1,
    region: item[0],
    theme: item[1],
    detail: item[2],
  }));
  return injectSportsIntoItinerary(days, sportPlaces);
}

function injectSportsIntoItinerary(days, sportPlaces) {
  const updated = days.map((day) => ({ ...day }));
  sportPlaces.forEach((place) => {
    const targetIndex = findDayIndexForRegion(updated, REGION_LABELS[place.region] || place.region);
    if (targetIndex >= 0) {
      const label = place.type === "golf" ? "高尔夫" : "网球";
      updated[targetIndex].detail += ` ${label}选配：${place.name}（${place.duration}）。`;
    }
  });
  return updated;
}

function findDayIndexForRegion(days, regionLabel) {
  const index = days.findIndex((day) => day.region === regionLabel);
  if (index >= 0) return index;
  return days.findIndex((day) => day.region !== "返程" && day.region !== "选配");
}

function createPlan(input = {}) {
  const modules = normalizeModules(input.modules);
  const inferredProgramType = modules.length ? inferProgramTypeFromModules(modules) : input.programType;
  const preferences = {
    healing: clampNumber((input.healing ?? 4) + getModuleBoost(modules, "healing"), 1, 5),
    vacation: clampNumber((input.vacation ?? 4) + getModuleBoost(modules, "vacation"), 1, 5),
    comfort: clampNumber((input.comfort ?? 4) + getModuleBoost(modules, "comfort"), 1, 5),
    sports: normalizeSportTypes(input.sports ?? []),
  };
  const durationDays = clampNumber(input.durationDays ?? 7, 5, 8);
  const programType = inferredProgramType || "healing-vacation";
  const plan = buildDayPlan(programType, durationDays, preferences);
  const hotelTier = HOTEL_TIERS[input.hotelTier] ? input.hotelTier : "fiveStar";
  const quarter = QUARTERS[input.quarter] ? input.quarter : "q2";
  const travelers = clampNumber(input.travelers ?? 2, 1, 12);
  const modulePlaces = getModulePlaces(modules);
  const selected = mergeSelectedPlaces(plan.selected, modulePlaces);
  const suggestedPrice = getQuarterlyPriceRange(programType, durationDays, hotelTier, quarter);
  const profitModel = calculateProfitModel({
    programType,
    durationDays,
    hotelTier,
    quarter,
    travelers,
    modules,
    sports: preferences.sports,
    priceRange: suggestedPrice,
  });
  const hotelMaterials = getHotelStayMaterials(plan.route, hotelTier);

  return {
    preferences,
    modules,
    hotelTier,
    quarter,
    travelers,
    durationDays,
    ...plan,
    selected,
    profitModel,
    hotelMaterials,
    commercial: {
      packageName: getPackageName(modules, plan.program.name, durationDays),
      suggestedPrice,
      positioning: plan.program.promise,
      hotelRule: `${HOTEL_TIERS[hotelTier].name} · ${HOTEL_TIERS[hotelTier].note}`,
      seasonalNote: `${QUARTERS[quarter].name} · ${QUARTERS[quarter].note}`,
      quoteCta: "提交偏好后生成报价摘要，可用于人工跟进酒店、课程和车辆报价。",
    },
  };
}

function getHotelStayMaterials(route, hotelTier) {
  const routeRegions = new Set(route.map((step) => step.region));
  return HOTEL_STAY_MATERIALS.filter((hotel) => routeRegions.has(hotel.region) && hotel.tiers.includes(hotelTier));
}

function calculateProfitModel({ programType, durationDays, hotelTier, quarter, travelers, modules, sports, priceRange }) {
  const nights = durationDays - 1;
  const price = parsePriceRange(priceRange);
  const hotelNight = getHotelNightCost(hotelTier, quarter);
  const experienceCost = getExperienceCost(programType, modules, sports);
  const vehicleCost = 900 + Math.max(0, durationDays - 5) * 180;
  const conciergeCost = 650 + durationDays * 120;
  const insuranceCost = 0;
  const contingencyRate = 0.08;

  const perPersonBase =
    hotelNight * nights +
    experienceCost +
    vehicleCost / Math.max(1, travelers) +
    conciergeCost / Math.max(1, travelers) +
    insuranceCost;
  const perPersonCost = roundPrice(perPersonBase * (1 + contingencyRate));
  const lowProfit = price.low - perPersonCost;
  const highProfit = price.high - perPersonCost;
  const lowMargin = Math.round((lowProfit / price.low) * 100);
  const highMargin = Math.round((highProfit / price.high) * 100);

  return {
    travelers,
    perPersonCost,
    groupCost: perPersonCost * travelers,
    perPersonProfit: { low: lowProfit, high: highProfit },
    groupProfit: { low: lowProfit * travelers, high: highProfit * travelers },
    margin: { low: lowMargin, high: highMargin },
    breakdown: {
      hotelPerNight: hotelNight,
      hotelTotal: hotelNight * nights,
      experiences: experienceCost,
      vehicleShare: roundPrice(vehicleCost / Math.max(1, travelers)),
      conciergeShare: roundPrice(conciergeCost / Math.max(1, travelers)),
      insurance: insuranceCost,
      insuranceNote: "保险不计入套餐成本，建议客户自行购买覆盖巴厘岛当地医疗、意外、延误和高风险活动的旅行保险。",
      contingencyRate,
    },
    warning: lowMargin < 25 ? "毛利偏低，需要提高售价或降低酒店/体验成本。" : "毛利区间可接受，仍需用真实房价复核。",
  };
}

function getHotelNightCost(hotelTier, quarter) {
  const base = {
    fiveStar: 1350,
    cliffLuxury: 2600,
  }[hotelTier] || 1350;
  return roundPrice(base * QUARTERS[quarter].multiplier);
}

function getExperienceCost(programType, modules, sports) {
  let cost = 1500;
  if (programType === "subconscious-healing") cost += 900;
  if (programType === "deep-healing") cost += 700;
  if (modules.includes("body")) cost += 650;
  if (modules.includes("spiritual")) cost += 650;
  if (modules.includes("vacation")) cost += 300;
  if (modules.includes("sightseeing")) cost += 280;
  if (sports.includes("tennis")) cost += 450;
  if (sports.includes("golf")) cost += 1200;
  return cost;
}

function normalizeModules(modules = []) {
  if (!Array.isArray(modules)) return [];
  return modules.filter((module) => MODULES[module]);
}

function getPackageName(modules, fallbackName, durationDays) {
  if (!modules.length) return `${durationDays}天${fallbackName}`;
  const names = modules.map((module) => MODULES[module].name);
  if (names.length === 1) return `${durationDays}天${names[0]}定制旅修`;
  if (names.length === 2) return `${durationDays}天${names[0]} + ${names[1]}旅修`;
  return `${durationDays}天${names.slice(0, -1).join(" + ")} + ${names.at(-1)}定制`;
}

function inferProgramTypeFromModules(modules) {
  if (modules.includes("movement") && !modules.includes("spiritual")) return "sport-reset";
  if (modules.includes("spiritual") && !modules.includes("vacation")) return "subconscious-healing";
  if (modules.includes("spiritual") && modules.includes("body")) return "subconscious-healing";
  if (modules.includes("vacation")) return "healing-vacation";
  return "healing-vacation";
}

function getModuleBoost(modules, key) {
  return modules.reduce((sum, module) => sum + (MODULES[module].preferenceBoost[key] || 0), 0);
}

function getModulePlaces(modules) {
  const ids = [...new Set(modules.flatMap((module) => MODULES[module].placeIds))];
  return ids
    .map((id) => PLACES.find((place) => place.id === id))
    .filter(Boolean)
    .map((place) => ({ ...place, status: "模块推荐", rank: 0 }));
}

function mergeSelectedPlaces(selected, additions) {
  const byId = new Map();
  [...selected, ...additions].forEach((place) => {
    if (!byId.has(place.id)) byId.set(place.id, place);
  });
  return [...byId.values()];
}

function getQuarterlyPriceRange(programType, durationDays, hotelTier, quarter) {
  const base = parsePriceRange(getPriceRange(programType, durationDays));
  const multiplier = HOTEL_TIERS[hotelTier].multiplier * QUARTERS[quarter].multiplier;
  const low = roundPrice(base.low * multiplier);
  const high = roundPrice(base.high * multiplier);
  return `${low}-${high} 元/人`;
}

function parsePriceRange(range) {
  const matches = range.match(/(\d+)-(\d+)/);
  if (!matches) return { low: 9990, high: 13900 };
  return { low: Number(matches[1]), high: Number(matches[2]) };
}

function roundPrice(value) {
  return Math.round(value / 100) * 100;
}

function getPriceRange(programType, durationDays) {
  if (programType === "deep-healing") return durationDays >= 7 ? "11900-16900 元/人" : "8990-12900 元/人";
  if (programType === "subconscious-healing") return durationDays >= 7 ? "13900-18900 元/人" : "10900-14900 元/人";
  if (programType === "sport-reset") return durationDays >= 7 ? "10900-15900 元/人" : "8990-12900 元/人";
  return durationDays >= 7 ? "12900-17900 元/人" : "9990-13900 元/人";
}


const customerForm = document.querySelector("#customerPlannerForm");
const customerProgramName = document.querySelector("#customerProgramName");
const customerProgramPromise = document.querySelector("#customerProgramPromise");
const customerPrice = document.querySelector("#customerPrice");
const customerRouteOutput = document.querySelector("#customerRouteOutput");
const customerItinerary = document.querySelector("#customerItinerary");

function getCustomerInput() {
  const formData = new FormData(customerForm);
  return {
    programType: formData.get("programType"),
    durationDays: Number(formData.get("durationDays")),
    hotelTier: formData.get("hotelTier"),
    quarter: formData.get("quarter"),
    travelers: 2,
  };
}

function renderCustomerPlan() {
  const plan = createPlan(getCustomerInput());
  customerProgramName.textContent = plan.commercial.packageName;
  customerProgramPromise.textContent = plan.commercial.positioning;
  customerPrice.textContent = plan.commercial.suggestedPrice;
  customerRouteOutput.innerHTML = renderCustomerRoute(plan);
  customerItinerary.innerHTML = renderCustomerItinerary(plan);
}

function renderCustomerRoute(plan) {
  const routePlaces = getRoutePlaces(plan);
  return `
    <div class="customer-route-summary">
      <article>
        <span>天数</span>
        <strong>${plan.durationDays}天${plan.durationDays - 1}晚</strong>
        <p>${HOTEL_TIERS[plan.hotelTier].name} · ${QUARTERS[plan.quarter].name}</p>
      </article>
      <article>
        <span>路线</span>
        <strong>${plan.route.map((step) => step.label).join(" → ")}</strong>
        <p>核心地点：${routePlaces.map((place) => place.name).join("、")}</p>
      </article>
      <article>
        <span>节奏</span>
        <strong>${getCustomerPace(plan)}</strong>
        <p>保留酒店恢复、自由整合和低刺激晚间安排。</p>
      </article>
    </div>
    <div class="customer-route-chain">
      ${plan.route
        .map(
          (step, index) => `
            <article>
              <b>${index + 1}</b>
              <strong>${step.label}</strong>
              <span>${step.nights}晚 · ${getRegionRole(step.region)}</span>
            </article>
          `,
        )
        .join("")}
    </div>
  `;
}

function renderCustomerItinerary(plan) {
  return plan.days
    .map(
      (day) => `
        <article class="customer-day-card">
          <header>
            <span>Day ${day.day}</span>
            <strong>${escapeHtml(day.region)}</strong>
          </header>
          <h3>${escapeHtml(day.theme)}</h3>
          <p>${escapeHtml(day.detail)}</p>
          <div>
            <span>${getCustomerDayTag(day)}</span>
            <span>${getCustomerTransferNote(day)}</span>
          </div>
        </article>
      `,
    )
    .join("");
}

function getRoutePlaces(plan) {
  const routeRegions = new Set(plan.route.map((step) => step.region));
  const seen = new Set();
  return plan.selected
    .filter((place) => routeRegions.has(place.region))
    .filter((place) => {
      if (seen.has(place.id)) return false;
      seen.add(place.id);
      return true;
    })
    .slice(0, 8);
}

function getCustomerPace(plan) {
  if (plan.programType === "deep-healing" || plan.programType === "subconscious-healing") return "深度疗愈节奏";
  if (plan.programType === "sport-reset") return "轻运动恢复节奏";
  return "疗愈度假平衡节奏";
}

function getCustomerDayTag(day) {
  if (day.region === "返程") return "旅后整合";
  if (day.region === "选配") return "弹性安排";
  if (day.detail.includes("转场")) return "转场日";
  if (day.detail.includes("水疗") || day.detail.includes("SPA") || day.detail.includes("护理")) return "身体恢复";
  if (day.detail.includes("声音") || day.detail.includes("冥想") || day.detail.includes("潜意识")) return "向内探索";
  return "低负担体验";
}

function getCustomerTransferNote(day) {
  if (day.day === 1) return "含接机安排";
  if (day.region === "返程") return "含送机安排";
  if (day.region === "选配") return "按选配确认";
  return "专车/短接驳";
}

function getRegionRole(region) {
  const roles = {
    ubud: "雨林、瑜伽、音疗和身体修复",
    seseh: "海边排毒、声音和身体打开",
    canggu: "轻运动、社交和身体能量",
    "nusa-dua": "稳定、舒适、沙滩和度假恢复",
    uluwatu: "悬崖、日落、水疗和旅修收束",
    tabanan: "自然仪式和古树冥想",
  };
  return roles[region] || REGION_LABELS[region] || "定制体验";
}

function escapeHtml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

customerForm.addEventListener("input", renderCustomerPlan);
customerForm.addEventListener("change", renderCustomerPlan);

renderCustomerPlan();
